import{_ as l,o as i,c as e,ag as o}from"./chunks/framework.DNt_9s2P.js";const h=JSON.parse('{"title":"TODO / 課題管理","description":"","frontmatter":{},"headers":[],"relativePath":"guide/todo.md","filePath":"guide/todo.md"}'),t={name:"guide/todo.md"};function r(n,a,d,s,c,u){return i(),e("div",null,[...a[0]||(a[0]=[o('<h1 id="todo-課題管理" tabindex="-1">TODO / 課題管理 <a class="header-anchor" href="#todo-課題管理" aria-label="Permalink to &quot;TODO / 課題管理&quot;">​</a></h1><p>Luna (LMS) の課題・提出物を一元管理します。</p><h2 id="課題一覧" tabindex="-1">課題一覧 <a class="header-anchor" href="#課題一覧" aria-label="Permalink to &quot;課題一覧&quot;">​</a></h2><p>Luna に登録されている課題をリスト形式で表示します。</p><ul><li>未提出 / 提出済のステータス管理</li><li>締切日の表示</li><li>期限超過の課題は赤色で強調表示</li></ul><h2 id="課題の詳細" tabindex="-1">課題の詳細 <a class="header-anchor" href="#課題の詳細" aria-label="Permalink to &quot;課題の詳細&quot;">​</a></h2><p>課題をクリックすると、別ウィンドウで詳細を確認できます。</p><ul><li>課題の説明文</li><li>添付ファイル</li><li>提出状況</li></ul><h2 id="レポート提出" tabindex="-1">レポート提出 <a class="header-anchor" href="#レポート提出" aria-label="Permalink to &quot;レポート提出&quot;">​</a></h2><p>詳細ウィンドウから直接レポートを提出できます。</p><ol><li>課題の詳細を開く</li><li>ファイルを添付（ドラッグ&amp;ドロップまたはファイル選択）</li><li>コメントを入力（任意）</li><li>「提出」ボタンをクリック</li></ol><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p>提出は Luna のサーバーに直接送信されます。提出前に内容を十分確認してください。</p></div><h2 id="掲示板投稿" tabindex="-1">掲示板投稿 <a class="header-anchor" href="#掲示板投稿" aria-label="Permalink to &quot;掲示板投稿&quot;">​</a></h2><p>Luna の掲示板 (Forum) スレッドへの返信投稿にも対応しています。</p><h2 id="ai-学習アシスト" tabindex="-1">AI 学習アシスト <a class="header-anchor" href="#ai-学習アシスト" aria-label="Permalink to &quot;AI 学習アシスト&quot;">​</a></h2><p>OpenAI / Gemini API を使い、時間割・シラバス・締切を踏まえた学習計画を生成します。</p><ul><li>タスクごとの優先度と取り組み方ガイド</li><li>結果は 6 時間キャッシュされます</li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>AI 学習アシストを使用するには、設定画面で API キーを登録する必要があります。</p></div>',18)])])}const m=l(t,[["render",r]]);export{h as __pageData,m as default};
